// 1. Grab the raw text string from the AI node output
const rawText = $input.first().json.output;

try {
  // 2. Parse the string into a real, functional JavaScript object
  const resumeObj = JSON.parse(rawText);

  // 3. Convert it back into a human-readable string with proper indentation (2 spaces)
  const jsonString = JSON.stringify(resumeObj, null, 2);

  // 4. Convert that text string into an n8n binary file buffer
  const binaryData = Buffer.from(jsonString, 'utf-8');

  // Find the company name dynamically, or fallback to the second job role if the first isn't populated
  const company = resumeObj.experience?.[0]?.company || "Tailored-Job";

  return {
    json: {
      companyName: company,
      status: "success"
    },
    binary: {
      data: {
        data: binaryData.toString('base64'),
        mimeType: 'application/json',
        fileName: `${$('Get row(s)').first().json.id}_resume.json` // Cleans filename (e.g. Stripe_resume.json)
      }
    }
  };

} catch (error) {
  // Safe fallback case if the AI returns broken markdown or invalid JSON syntax
  const fallbackBinary = Buffer.from(rawText, 'utf-8');
  return {
    json: {
      companyName: "Error-Raw-Text",
      error: "Failed to parse AI response into valid JSON structure",
      details: error.message
    },
    binary: {
      data: {
        data: fallbackBinary.toString('base64'),
        mimeType: 'text/plain',
        fileName: 'raw_ai_output.txt'
      }
    }
  };
}
